sql:
SELECT student_id, COUNT(experience_id) AS number_of_experiences
FROM work_experiences
GROUP BY student_id;

SELECT name, age, gender, MAX(age) OVER (PARTITION BY country) AS max_age_in_country
FROM students
WHERE country = 'USA';

SELECT COUNT(*) AS verified_linkedin_accounts
FROM linkedin_accounts
WHERE verified = 1;

SELECT AVG(assignment_count) AS average_assignments_per_course
FROM (
  SELECT course_id, COUNT(*) AS assignment_count
  FROM assignments
  GROUP BY course_id
) AS subquery;

SELECT job_title, company
FROM work_experiences
WHERE start_date >= '2020-01-01' AND end_date <= '2021-12-31';

external_knowledge:
- Active enrollment refers to the current or ongoing enrollment status of a student in a course, as opposed to pending or completed enrollments; 
- Average grade is calculated by summing up all grades and dividing by the total number of grades; 
- Total assignments refer to the number of assignments that have been graded for each student in each course.
